CREATE TABLE IF NOT EXISTS areas (id BIGSERIAL PRIMARY KEY, name VARCHAR(80) NOT NULL UNIQUE, description VARCHAR(255) NOT NULL, responsible VARCHAR(120) NOT NULL);
CREATE TABLE IF NOT EXISTS warehouses (id BIGSERIAL PRIMARY KEY, name VARCHAR(80) NOT NULL UNIQUE, location VARCHAR(150) NOT NULL, description VARCHAR(255) NOT NULL, status VARCHAR(12) NOT NULL);
CREATE TABLE IF NOT EXISTS categories (id BIGSERIAL PRIMARY KEY, name VARCHAR(80) NOT NULL UNIQUE, description VARCHAR(255) NOT NULL);
CREATE TABLE IF NOT EXISTS units (id BIGSERIAL PRIMARY KEY, name VARCHAR(50) NOT NULL UNIQUE, abbreviation VARCHAR(10) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS suppliers (id BIGSERIAL PRIMARY KEY, name VARCHAR(120) NOT NULL, tax_id VARCHAR(30) NOT NULL UNIQUE, phone VARCHAR(30), email VARCHAR(120), address VARCHAR(180), city VARCHAR(80), status VARCHAR(12) NOT NULL);
CREATE TABLE IF NOT EXISTS products (id BIGSERIAL PRIMARY KEY, code VARCHAR(40) NOT NULL UNIQUE, name VARCHAR(120) NOT NULL, description VARCHAR(500) NOT NULL, category_id BIGINT NOT NULL REFERENCES categories(id), unit_id BIGINT NOT NULL REFERENCES units(id), supplier_id BIGINT REFERENCES suppliers(id), minimum_stock NUMERIC(12,2) NOT NULL, maximum_stock NUMERIC(12,2), average_cost NUMERIC(12,2) NOT NULL, perishable BOOLEAN NOT NULL, lot_control BOOLEAN NOT NULL, expiration_control BOOLEAN NOT NULL, status VARCHAR(12) NOT NULL);
